import re
import semantic_kernel as sk

PII_PATTERNS = [
    r'\b(?:\d{3}[-.]?){2}\d{4}\b',  # SSN
    r'\b\d{3}-?\d{2}-?\d{4}\b',     # SSN alt
    r'\b4[0-9]{12}(?:[0-9]{3})?\b',   # Visa
    r'\b5[1-5][0-9]{14}\b',          # Mastercard
    r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'  # Email
]

def scan_for_pii(text: str) -> list:
    findings = []
    for pattern in PII_PATTERNS:
        matches = re.finditer(pattern, text)
        for match in matches:
            findings.append({
                'pattern': pattern,
                'match': match.group(),
                'start': match.start(),
                'end': match.end()
            })
    return findings

# Kernel function result filter
kernel = sk.Kernel()

@kernel.register_function(
    plugin_name='security',
    function_name='check_pii'
)
def check_pii_result(input: str) -> str:
    pii = scan_for_pii(input)
    if pii:
        raise ValueError(f'PII detected: {len(pii)} matches found')
    return input

from semantic_kernel.memory import SemanticTextMemory
import re

class MemoryLeakDetector:
    def __init__(self):
        self.pii_patterns = [
            r'\b\d{3}-\d{2}-\d{4}\b',
            r'[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}',
            r'\b[A-Z0-9]{5}\b'  # API Key pattern
        ]

    def scan_memory(self, memory: SemanticTextMemory, collection_name: str):
        records = memory.search(collection_name, '', limit=10)
        leaks = []
        for record in records:
            for pattern in self.pii_patterns:
                if re.search(pattern, record.text):
                    leaks.append({
                        'record_id': record.id,
                        'collection': collection_name,
                        'text_preview': record.text[:100],
                        'pattern': pattern
                    })
        return leaks

# Usage
detector = MemoryLeakDetector()
leaks = detector.scan_memory(kernel.memory_store, 'chat_history')
if leaks:
    print(f'Found {len(leaks)} memory leaks')

import json
from semantic_kernel.planning import ActionPlanner
import re

class PlanLeakMonitor:
    def __init__(self):
        self.sensitive_patterns = [r'[A-Za-z0-9]{32,}', r'Bearer\s+[A-Za-z0-9._-]+']

    def inspect_plan(self, plan_json: str):
        try:
            plan = json.loads(plan_json)
            leaks = []
            def scan_node(node):
                if isinstance(node, dict):
                    for k, v in node.items():
                        if isinstance(v, str) and any(re.search(p, v) for p in self.sensitive_patterns):
                            leaks.append({'key': k, 'value_preview': v[:20] + '...'})
                        scan_node(v)
                elif isinstance(node, list):
                    for item in node:
                        scan_node(item)
            scan_node(plan)
            return leaks
        except:
            return []

