import re
import semantic_kernel as sk
from typing import Callable

class PIIRedactor:
    def __init__(self):
        self.redact_patterns = {
            r'\b\d{3}-\d{2}-\d{4}\b': '[SSN]',
            r'[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}': '[EMAIL]',
            r'\b[A-Z0-9a-z]{32,}\b': '[KEY]',
            r'\b4[0-9]{12}(?:[0-9]{3})?\b': '[CARD]'
        }

    def redact(self, text: str) -> str:
        for pattern, replacement in self.redact_patterns.items():
            text = re.sub(pattern, replacement, text)
        return text

# Global kernel filter
redactor = PIIRedactor()

def result_filter(result: str) -> str:
    return redactor.redact(result)

# Apply to all kernel functions
kernel = sk.Kernel()
kernel.filters.add(result_filter)

from semantic_kernel.planning import SequentialPlanner
import semantic_kernel as sk

class SafePlanner:
    def __init__(self, kernel: sk.Kernel):
        self.planner = SequentialPlanner(kernel)
        self.redactor = PIIRedactor()

    def create_safe_plan(self, goal: str):
        plan = self.planner.create_plan(goal)

        # Sanitize plan parameters
        safe_steps = []
        for step in plan._steps:
            safe_params = {
                k: self.redactor.redact(str(v)) if isinstance(v, str) else v
                for k, v in step.parameters.items()
            }
            safe_step = step._replace(parameters=safe_params)
            safe_steps.append(safe_step)

        plan._steps = safe_steps
        return plan

    async def execute_safe(self, plan):
        # Execute with sanitized parameters
        result = ''
        for step in plan._steps:
            function = kernel.functions.get_function(step.plugin_name, step.function_name)
            result += await kernel.run_async(function, **step.parameters)
        return self.redactor.redact(str(result))

# Usage
safe_planner = SafePlanner(kernel)
plan = safe_planner.create_safe_plan('Analyze customer data')
result = await safe_planner.execute_safe(plan)
